import{_ as t,o as r,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const s="/images/uebung029.jpg",c=JSON.parse('{"title":"Übung Lektion 19","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung19.md","filePath":"lektionen/uebung19.md"}'),a={name:"lektionen/uebung19.md"};function p(d,e,o,h,b,l){return r(),i("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-19" tabindex="-1">Übung Lektion 19 <a class="header-anchor" href="#ubung-lektion-19" aria-label="Permalink to &quot;Übung Lektion 19&quot;">​</a></h1><p>Übersetzen Sie ins Sanskrit:</p><p>1. Die Vaiśyafrau, deren Sohn gestorben ist, weint. यस्या वैश्यायाः पुत्रो मृतः सा रोदिति । यस्या वैश्यायाः पुत्रो मृतो रोदिति ।</p><p>2. Rāma opfert der Gottheit, die ihn behütet. या देवता रामं रक्षति तां यजते ।</p><p>3. Der Dichter preist den Kṣatriya, dessen Reichtum er begehrt. यस्य क्षत्रियस्य धनं लुभ्यति तं कविः सतुति ।</p><p>4. Feuer verbrennt das Haus des Mannes, der Agni nicht mit einem Opfer verehrt. यो नरो ऽग्निं न यजते तस्य गृहमग्निर्दहति ।</p><p>5. Der tigergleiche Mann erschlägt die Kṣatriya-Krieger, die Rāma besieget haben (Passiv). यैः क्षत्रिययोधै रामो जितस्तान्पुरुषव्याघ्रो हन्ति ॥</p><p>Übersetzen Sie:</p><p>येन येन च वातेन<br> वारिदो वारि मुञ्चति ।<br> तेन तेन च वातेन<br> छत्रं वहति पण्डितः ॥१॥</p><p>Mit welchem Wind die Wolke Wasser lässt, mit dem Wind bewegt ein Gelehrter seinen Schirm.</p><p>Entspricht den deutschen Sprichwörtern:</p><blockquote><p>Hinter dem Winde schifft der Kluge.</p><p>Je nach dem Winde dreht sich die Fahne.</p><p>Jeder fängt den Wind in seinem Segel.</p></blockquote><p>यो धर्ममर्थं कामं च<br> यथाकालं निषेवते ।<br> धर्मार्थकामसंयोगं<br> सो ऽमुत्रेह च विन्दति ॥२॥</p><p>Wer zur rechten Zeit Religion, gewinnbringender Tätigkeit bzw. Liebe frönt, der findet auf dieser Welt und im Jenseits Gemeinschaft mit Religion, Gewinn und Liebe.</p><p>सा भार्या या प्रियं ब्रूते<br> स पुत्रो यस्तु जीवति ।<br> स जीवति गुणो यस्य<br> धर्मो यस्य स जीवति ॥३॥</p><p>Das ist seine Gattin, die Liebes spricht,<br> Das ist aber ein Sohn, der lebt,<br> Der lebt, der Tugend hat,<br> Wer Religion, Recht und Sitte hat, der lebt.</p><p>यस्यार्थास्तस्य मित्राणि<br> यस्यार्थास्तस्य बान्धवाः ।<br> यस्यार्थाः स पुमांल्लोके<br> यस्यार्थाः स हि पण्डितः ॥४॥</p><p>Wer Wohlstand hat, der hat Freunde,<br> Wer Wohlstand hat, der hat Verwandte,<br> Wer Wohlstand hat, der ist in der Welt ein Mann,<br> Wer nämlich Wohlstand hat, der ist ein Gelehrter.</p><p><img src="'+s+'" alt=""><br> Abb.: यस्यार्थास्तस्य मित्राणि<br> यस्यार्थास्तस्य बान्धवाः ।<br> यस्यार्थाः स पुमांल्लोके<br> यस्यार्थाः स हि पण्डितः ॥<br> &quot;An 1895 group photograph of the eleven year old Krishnaraja Wadiyar IV (ನಾಲ್ವಡಿ ಕೃಷ್ಣರಾಜ ಒಡೆಯರು), ruler of the princely state of Mysore (ಮೈಸೂರು ಸಾಮ್ರಾಜ್ಯ) in South India, with his brothers and sisters.&quot;<br> [Bildquelle: Wikipedia. Public domain]</p>',20)])])}const g=t(a,[["render",p]]);export{c as __pageData,g as default};
